mapper.select:
/* select * FROM withdrawlog W,cpinfo c ,user u WHERE W.AppId = C.AppId*/
SELECT *
FROM withdrawlog

SELECT * FROM withdrawlog w left join cpinfo c on w.AppId = c.AppId left join withdrawtype wd on
w.WithdrawTypeId=wd.Id
where w.AppId = #{appId}

    and
    w.Id = #{Id}


    and
    w.OrderId = #{OrderId}


    and
    w.Type = #{Type}


    and
    w.WithdrawTypeId = #{typeid}



    and
    w.Status = #{Status}


    and
    w.CreateTime >= #{startTime}


    and
    w.CreateTime <= #{endTime}



order by w.CreateTime desc

    limit ${rowIndex},${limit}

SELECT count(w.Id) FROM withdrawlog w left join cpinfo c on w.AppId = c.AppId left join withdrawtype wd on
w.WithdrawTypeId=wd.Id
where w.AppId = #{appId}

    and
    w.Id = #{Id}


    and
    w.OrderId = #{OrderId}


    and
    w.Type = #{Type}


    and
    w.WithdrawTypeId = #{typeid}



    and
    w.Status = #{Status}


    and
    w.CreateTime >= #{startTime}


    and
    w.CreateTime <= #{endTime}

SELECT count(*) FROM withdrawlog w left join cpinfo c on w.AppId = c.AppId left join withdrawtype wd on
w.WithdrawTypeId=wd.Id
where 1=1

    and
    w.AppId = #{appId}


    and
    w.Id = #{id}


    and
    w.OrderId = #{orderId}


    and
    w.Status = #{status}


    and
    w.CreateTime = #{CreateTime}

order by w.CreateTime desc

SELECT withdrawlog.Id, withdrawlog.AppId, withdrawlog.OrderId, withdrawlog.Amount, withdrawlog.PlatformFee, withdrawlog.Type, withdrawlog.BankCardNo, withdrawlog.BankCode, withdrawlog.BranchCode, withdrawlog.BankAccountName, withdrawlog.Currency, withdrawlog.Email, withdrawlog.Mobile, withdrawlog.`Status`, withdrawlog.CreateTime, withdrawlog.WithdrawTime, withdrawlog.Ip, withdrawlog.SyncCnt, withdrawlog.DocumentId, withdrawlog.PixType, withdrawlog.PixKey, withdrawlog.utr, withdrawlog.NotifyUrl FROM withdrawlog WHERE withdrawlog.AppId = #{appId}
and withdrawlog.Id = #{id}
and withdrawlog.OrderId like concat('%', #{orderId}, '%')
and ( ( withdrawlog.Status = 2 and withdrawlog.Status = #{status}) or ( if(#{status} = 1 or #{status} = -1 or #{status} = 0,(withdrawlog.Status = 1 or withdrawlog.Status = -1 or withdrawlog.Status = 0),false) ) or ( withdrawlog.Status = -2 and withdrawlog.Status = #{status}))
and withdrawlog.CreateTime >= #{startCreateTime}
and withdrawlog.CreateTime <= #{endCreateTime}
and withdrawlog.WithdrawTime >= #{startWithdrawTime}
and withdrawlog.WithdrawTime <= #{endWithdrawTime}
and withdrawlog.BankCardNo like concat('%', #{bankCardNo}, '%')
and withdrawlog.PixKey like concat('%', #{pix_key}, '%')
and withdrawlog.DoucunmentId like concat('%', #{cpf}, '%')
and ((SyncCnt >0 AND SyncCnt = #{syncCnt}) OR (SyncCnt = 0 AND SyncCnt = #{syncCnt}) OR (SyncCnt < 0 AND SyncCnt = #{syncCnt}))
order by withdrawlog.CreateTime desc
limit ${rowIndex},${limit}

SELECT sum( Amount ) AS totalNeedWithdrawAmount, count( 1 ) as allWithdrawNum , sum( IF( STATUS = 2, Amount, 0 )) AS totalWithdrawAmount, sum( IF ( STATUS = 2, PlatformFee, 0 ) ) AS totalWithdrawFee, count( IF ( STATUS = 2, Id, null ) ) AS totalWithdrawNum, sum( IF ( STATUS = 1, Amount, 0 ) ) AS totalPendingWithdrawAmount, sum( IF ( STATUS = - 2, Amount, 0 )) AS totalFailWithdrawAmount FROM withdrawlog WHERE withdrawlog.AppId = #{appId}
and withdrawlog.Id = #{id}
and withdrawlog.OrderId like concat('%', #{orderId}, '%')
and ( ( withdrawlog.Status = 2 and withdrawlog.Status = #{status}) or ( if(#{status} = 1 or #{status} = -1 or #{status} = 0,(withdrawlog.Status = 1 or withdrawlog.Status = -1 or withdrawlog.Status = 0),false) ) or ( withdrawlog.Status = -2 and withdrawlog.Status = #{status}))
and withdrawlog.CreateTime >= #{startCreateTime}
and withdrawlog.CreateTime <= #{endCreateTime}
and withdrawlog.WithdrawTime >= #{startWithdrawTime}
and withdrawlog.WithdrawTime <= #{endWithdrawTime}
and withdrawlog.BankCardNo like concat('%', #{bankCardNo}, '%')
and withdrawlog.PixKey like concat('%', #{pix_key}, '%')
and withdrawlog.DoucunmentId like concat('%', #{cpf}, '%')
and ((SyncCnt >0 AND SyncCnt = #{syncCnt}) OR (SyncCnt = 0 AND SyncCnt = #{syncCnt}) OR (SyncCnt < 0 AND SyncCnt = #{syncCnt}))

SELECT withdrawlog.Id, withdrawlog.AppId, withdrawlog.OrderId, round(withdrawlog.Amount/100,2) as Amount, round(withdrawlog.PlatformFee/100,2) as PlatformFee, withdrawlog.BankCardNo, withdrawlog.BankCode, withdrawlog.BankAccountName, withdrawlog.Email, withdrawlog.Mobile, if(withdrawlog.`Status` = 2,'成功',if(withdrawlog.`Status` = 1 or withdrawlog.`Status` = 0 or withdrawlog.`Status` = -1,'处理中','失败')) as `Status`, withdrawlog.CreateTime, withdrawlog.WithdrawTime FROM withdrawlog WHERE 1=1
and withdrawlog.Id = #{id}
and withdrawlog.AppId = #{appId}
and withdrawlog.OrderId like concat('%', #{orderId}, '%')
and ( ( withdrawlog.Status = 2 and withdrawlog.Status = #{status}) or ( if(#{status} = 1 or #{status} = -1 or #{status} = 0,(withdrawlog.Status = 1 or withdrawlog.Status = -1 or withdrawlog.Status = 0),false) ) or ( withdrawlog.Status = -2 and withdrawlog.Status = #{status}))
and withdrawlog.CreateTime >= #{startCreateTime}
and withdrawlog.CreateTime <= #{endCreateTime}
and withdrawlog.WithdrawTime >= #{startWithdrawTime}
and withdrawlog.WithdrawTime <= #{endWithdrawTime}
and withdrawlog.BankCardNo like concat('%', #{bankCardNo}, '%')
and withdrawlog.PixKey like concat('%', #{pix_key}, '%')
and withdrawlog.DoucunmentId like concat('%', #{cpf}, '%')
and ((SyncCnt >0 AND SyncCnt = #{syncCnt}) OR (SyncCnt = 0 AND SyncCnt = #{syncCnt}) OR (SyncCnt < 0 AND SyncCnt = #{syncCnt}))
order by withdrawlog.Id desc
